const body = $input.first().json.body || $input.first().json;
const SUPABASE_URL = $vars.SUPABASE_URL;
const SUPABASE_KEY = $vars.SUPABASE_KEY;
const GOOGLE_KEY = $vars.GOOGLE_MAPS_API_KEY;
const ANTHROPIC_KEY = $vars.ANTHROPIC_API_KEY;

// Determinar fonte dos dados
let vagaData = {};

if (body.titulo || body.cargo) {
  // Dados já estruturados (via webhook/API)
  vagaData = {
    titulo: body.titulo || body.cargo,
    empresa: body.empresa || $vars.EMPRESA_NOME,
    endereco_sede: body.endereco_sede || body.local_trabalho || '',
    raio_maximo_km: parseInt(body.raio_maximo_km || 15),
    requisitos_obrigatorios: Array.isArray(body.requisitos_obrigatorios) ? body.requisitos_obrigatorios : (body.requisitos_obrigatorios || '').split('|').map(r => r.trim()).filter(Boolean),
    requisitos_desejados: Array.isArray(body.requisitos_desejados) ? body.requisitos_desejados : (body.requisitos_desejados || '').split('|').map(r => r.trim()).filter(Boolean),
    salario_min: parseFloat(body.salario_min || 0),
    salario_max: parseFloat(body.salario_max || 0),
    regime: body.regime || 'CLT',
    responsavel_email: body.responsavel_email || body.email_responsavel || $vars.EMAIL_RH,
    responsavel_whatsapp: body.responsavel_whatsapp || '',
    descricao: body.descricao || '',
    prazo_candidatura: body.prazo_candidatura || null
  };
} else if (body.texto_vaga || body.subject) {
  // Via e-mail — usar Claude para extrair
  const texto = body.texto_vaga || body.text || body.body || '';
  try {
    const claudeBody = {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1024,
      system: 'Extraia dados da vaga e retorne SOMENTE JSON válido.',
      messages: [{ role: 'user', content: `Extraia em JSON: {titulo, empresa, endereco_sede, raio_maximo_km, requisitos_obrigatorios:[], requisitos_desejados:[], salario_min, salario_max, regime, descricao, prazo_candidatura}\n\n${texto}` }]
    };
    const resp = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify(claudeBody)
    });
    const data = await resp.json();
    const text = data.content?.[0]?.text || '{}';
    vagaData = JSON.parse(text.replace(/```json\n?|```/g, '').trim());
    vagaData.responsavel_email = body.from_email || $vars.EMAIL_RH;
    vagaData.empresa = vagaData.empresa || $vars.EMPRESA_NOME;
  } catch(e) {
    vagaData = { titulo: body.subject || 'Vaga sem título', empresa: $vars.EMPRESA_NOME, responsavel_email: $vars.EMAIL_RH };
  }
} else {
  return [{ json: { error: 'Dados da vaga não reconhecidos', body } }];
}

// Geocodificar endereço da sede
let lat = 0, lng = 0, enderecoFormatado = vagaData.endereco_sede || '';
if (vagaData.endereco_sede && GOOGLE_KEY) {
  try {
    const geoResp = await fetch(`https://maps.googleapis.com/maps/api/geocode/json?address=${encodeURIComponent(vagaData.endereco_sede)}&key=${GOOGLE_KEY}&language=pt-BR&region=br`);
    const geoData = await geoResp.json();
    const geocode = geoData.results?.[0];
    lat = geocode?.geometry?.location?.lat || 0;
    lng = geocode?.geometry?.location?.lng || 0;
    enderecoFormatado = geocode?.formatted_address || vagaData.endereco_sede;
  } catch(e) {}
}

// Inserir vaga no Supabase
const vagaParaSalvar = {
  titulo: vagaData.titulo || 'Vaga sem título',
  descricao: vagaData.descricao || '',
  empresa: vagaData.empresa || $vars.EMPRESA_NOME,
  responsavel_email: vagaData.responsavel_email || $vars.EMAIL_RH,
  responsavel_whatsapp: vagaData.responsavel_whatsapp || '',
  endereco_sede: enderecoFormatado,
  latitude_sede: lat,
  longitude_sede: lng,
  raio_maximo_km: parseInt(vagaData.raio_maximo_km || 15),
  requisitos_obrigatorios: vagaData.requisitos_obrigatorios || [],
  requisitos_desejados: vagaData.requisitos_desejados || [],
  salario_min: parseFloat(vagaData.salario_min || 0),
  salario_max: parseFloat(vagaData.salario_max || 0),
  regime: vagaData.regime || 'CLT',
  status: 'aberta',
  data_abertura: new Date().toISOString(),
  prazo_candidatura: vagaData.prazo_candidatura || null
};

let vagaId = null;
try {
  const resp = await fetch(`${SUPABASE_URL}/rest/v1/vagas`, {
    method: 'POST',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
    body: JSON.stringify(vagaParaSalvar)
  });
  const savedVaga = await resp.json();
  vagaId = Array.isArray(savedVaga) ? savedVaga[0]?.id : savedVaga?.id;
} catch(e) {}

return [{ json: { vaga_id: vagaId, vaga: vagaParaSalvar, success: !!vagaId } }];
